                {view === 'signup' && <SignupView onSwitchToLogin={() => switchView('login')} onSwitchToUserSignup={() => switchView('userSignup')} onSwitchToAgentSignup={() => switchView('agentSignup')} onSwitchToInvestorSignup={() => switchView('investorSignup')} />}
