            .btn-secondary {
                @apply bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-200 px-5 py-3 rounded-lg font-semibold hover:bg-slate-200 dark:hover:bg-slate-600 transition-all;
            }
        `}</style>
    </div>
  );
};

